const d = $input.first().json;
// d = { type: 'grocery'|'medical', store/hospital, total, currency, items[], claimNote }

const isGrocery = d.type === 'grocery';
const place = isGrocery ? d.store : d.hospital;
const emoji = isGrocery ? '🛒' : '🏥';
const topItems = (d.items ?? []).slice(0, 3).map(i => i.name || i.description || 'Item').join(', ');

const message = [
  `${emoji} New expense logged!`,
  ``,
  `📍 ${place}`,
  `💰 ${d.currency ?? 'MYR'} ${Number(d.total).toFixed(2)}`,
  topItems ? `📦 Includes: ${topItems}${d.items?.length > 3 ? ` +${d.items.length - 3} more` : ''}` : null,
  ``,
  d.claimNote ? `💡 ${d.claimNote}` : null,
].filter(Boolean).join('\n');

return [{ json: { message } }];
